     2→
     3→/**
     4→ * Interactive MarkMap Renderer
     5→ *
     6→ * Extended version of MarkMapRenderer with support for real-time modifications
     7→ * via voice commands. Exposes an imperative handle for programmatic control.
     8→ *
     9→ * Part of Phase 7: Voice Commands for Mindmaps
    10→ */
    11→
    12→import {
    13→  useEffect,
    14→  useRef,
    15→  useState,
    16→  useCallback,
    17→  forwardRef,
    18→  useImperativeHandle,
    19→} from 'react';
    20→import { motion } from 'framer-motion';
    21→import { Markmap } from 'markmap-view';
    22→import { Transformer } from 'markmap-lib';
    23→import {
    24→  Printer,
    25→  Download,
    26→  ZoomIn,
    27→  ZoomOut,
    28→  Accessibility,
    29→  RotateCcw,
    30→  Maximize,
    31→  Minimize,
    32→  Undo2,
    33→} from 'lucide-react';
    34→import { cn } from '@/lib/utils';
    35→import { logger } from '@/lib/logger';
    36→import { useAccessibilityStore } from '@/lib/accessibility/accessibility-store';
    37→import { nanoid } from 'nanoid';
    38→import type { MindmapNode } from './markmap-renderer';
    39→
    40→// ============================================================================
    41→// TYPES
    42→// ============================================================================
    43→
    44→// Color name to hex mapping for Italian color commands
    45→const COLOR_MAP: Record<string, string> = {
    46→  rosso: '#ef4444',
    47→  red: '#ef4444',
    48→  blu: '#3b82f6',
    49→  blue: '#3b82f6',
    50→  verde: '#10b981',
    51→  green: '#10b981',
    52→  giallo: '#facc15',
    53→  yellow: '#facc15',
    54→  arancione: '#f97316',
    55→  orange: '#f97316',
    56→  viola: '#8b5cf6',
    57→  purple: '#8b5cf6',
    58→  rosa: '#ec4899',
    59→  pink: '#ec4899',
    60→};
    61→
    62→// Props for the interactive renderer
    63→export interface InteractiveMarkMapRendererProps {
    64→  title: string;
    65→  initialMarkdown?: string;
    66→  initialNodes?: MindmapNode[];
    67→  className?: string;
    68→  onNodesChange?: (nodes: MindmapNode[]) => void;
    69→}
    70→
    71→// Imperative handle exposed by the component
    72→export interface InteractiveMarkMapHandle {
    73→  // Modification methods
    74→  addNode: (concept: string, parentNodeLabel?: string) => boolean;
    75→  expandNode: (nodeLabel: string, suggestions?: string[]) => boolean;
    76→  deleteNode: (nodeLabel: string) => boolean;
    77→  focusNode: (nodeLabel: string) => boolean;
    78→  setNodeColor: (nodeLabel: string, color: string) => boolean;
    79→  connectNodes: (nodeALabel: string, nodeBLabel: string) => boolean;
    80→
    81→  // View methods
    82→  zoomIn: () => void;
    83→  zoomOut: () => void;
    84→  resetView: () => void;
    85→  toggleFullscreen: () => Promise<void>;
    86→
    87→  // State methods
    88→  getNodes: () => MindmapNode[];
    89→  setNodes: (nodes: MindmapNode[]) => void;
    90→  undo: () => boolean;
    91→}
    92→
    93→// Transformer instance for markdown parsing
    94→const transformer = new Transformer();
    95→
    96→// ============================================================================
    97→// HELPER FUNCTIONS
    98→// ============================================================================
    99→
   100→// Convert markdown to nodes (simplified parsing)
   101→function markdownToNodes(markdown: string): MindmapNode[] {
   102→  const lines = markdown.split('\n').filter((line) => line.trim());
   103→  const root: MindmapNode[] = [];
   104→  const stack: { node: MindmapNode; depth: number }[] = [];
   105→
   106→  for (const line of lines) {
   107→    const match = line.match(/^(#+)\s+(.+)$/);
   108→    if (!match) continue;
   109→
   110→    const depth = match[1].length;
   111→    const label = match[2].trim();
   112→    const node: MindmapNode = {
   113→      id: nanoid(8),
   114→      label,
   115→      children: [],
   116→    };
   117→
   118→    if (depth === 1) {
   119→      // This is the root title, skip
   120→      continue;
   121→    }
   122→
   123→    // Find parent at depth - 1
   124→    while (stack.length > 0 && stack[stack.length - 1].depth >= depth) {
   125→      stack.pop();
   126→    }
   127→
   128→    if (stack.length === 0) {
   129→      root.push(node);
   130→    } else {
   131→      const parent = stack[stack.length - 1].node;
   132→      if (!parent.children) parent.children = [];
   133→      parent.children.push(node);
   134→    }
   135→
   136→    stack.push({ node, depth });
   137→  }
   138→
   139→  return root;
   140→}
   141→
   142→// Convert structured nodes to markdown format
   143→function nodesToMarkdown(nodes: MindmapNode[], title: string): string {
   144→  const buildMarkdown = (node: MindmapNode, depth: number): string => {
   145→    const prefix = '#'.repeat(depth + 1);
   146→    let result = `${prefix} ${node.label}\n`;
   147→
   148→    if (node.children && node.children.length > 0) {
   149→      for (const child of node.children) {
   150→        result += buildMarkdown(child, depth + 1);
   151→      }
   152→    }
   153→
   154→    return result;
   155→  };
   156→
   157→  let markdown = `# ${title}\n`;
   158→  for (const node of nodes) {
   159→    markdown += buildMarkdown(node, 1);
   160→  }
   161→
   162→  return markdown;
   163→}
   164→
   165→// Find a node by label (case-insensitive, partial match)
   166→function findNodeByLabel(
   167→  nodes: MindmapNode[],
   168→  label: string
   169→): { node: MindmapNode; parent: MindmapNode | null; index: number } | null {
   170→  const normalizedLabel = label.toLowerCase().trim();
   171→
   172→  const search = (
   173→    nodeList: MindmapNode[],
   174→    parent: MindmapNode | null
   175→  ): { node: MindmapNode; parent: MindmapNode | null; index: number } | null => {
   176→    for (let i = 0; i < nodeList.length; i++) {
   177→      const node = nodeList[i];
   178→      if (node.label.toLowerCase().includes(normalizedLabel)) {
   179→        return { node, parent, index: i };
   180→      }
   181→      if (node.children && node.children.length > 0) {
   182→        const found = search(node.children, node);
   183→        if (found) return found;
   184→      }
   185→    }
   186→    return null;
   187→  };
   188→
   189→  return search(nodes, null);
   190→}
   191→
   192→// Deep clone nodes
   193→function cloneNodes(nodes: MindmapNode[]): MindmapNode[] {
   194→  return JSON.parse(JSON.stringify(nodes));
   195→}
   196→
   197→// ============================================================================
   198→// COMPONENT
   199→// ============================================================================
   200→
   201→export const InteractiveMarkMapRenderer = forwardRef<
   202→  InteractiveMarkMapHandle,
   203→  InteractiveMarkMapRendererProps
   204→>(function InteractiveMarkMapRenderer(
   205→  { title, initialMarkdown, initialNodes, className, onNodesChange },
   206→  ref
   207→) {
   208→  const svgRef = useRef<SVGSVGElement>(null);
   209→  const containerRef = useRef<HTMLDivElement>(null);
   210→  const markmapRef = useRef<Markmap | null>(null);
   211→
   212→  const [error, setError] = useState<string | null>(null);
   213→  const [rendered, setRendered] = useState(false);
   214→  const [zoom, setZoom] = useState(1);
   215→  const [accessibilityMode, setAccessibilityMode] = useState(false);
   216→  const [isFullscreen, setIsFullscreen] = useState(false);
   217→
   218→  // Internal node state for modifications
   219→  const [nodes, setNodesState] = useState<MindmapNode[]>(() => {
   220→    if (initialNodes && initialNodes.length > 0) {
   221→      return cloneNodes(initialNodes);
   222→    }
   223→    if (initialMarkdown) {
   224→      return markdownToNodes(initialMarkdown);
   225→    }
   226→    return [];
