   858→            {isFullscreen ? <Minimize className="w-4 h-4" /> : <Maximize className="w-4 h-4" />}
   859→          </button>
   860→
   861→          {/* Download */}
   862→          <button
   863→            onClick={() => {
   864→              // Simplified download for now
   865→              const markdown = nodesToMarkdown(nodes, title);
   866→              const blob = new Blob([markdown], { type: 'text/markdown' });
   867→              const url = URL.createObjectURL(blob);
   868→              const a = document.createElement('a');
   869→              a.href = url;
   870→              a.download = `mappa-mentale-${title.toLowerCase().replace(/\s+/g, '-')}.md`;
   871→              a.click();
   872→              URL.revokeObjectURL(url);
   873→            }}
   874→            className={cn(
   875→              'p-2 rounded-lg transition-colors',
   876→              settings.highContrast
   877→                ? 'bg-yellow-400 text-black hover:bg-yellow-300'
   878→                : 'bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600'
   879→            )}
   880→            title="Scarica Markdown"
   881→            aria-label="Scarica mappa come Markdown"
   882→          >
   883→            <Download className="w-4 h-4" />
   884→          </button>
   885→
   886→          {/* Print */}
   887→          <button
   888→            onClick={() => window.print()}
   889→            className={cn(
   890→              'p-2 rounded-lg transition-colors',
   891→              settings.highContrast
   892→                ? 'bg-yellow-400 text-black hover:bg-yellow-300'
   893→                : 'bg-accent-themed text-white hover:brightness-110'
   894→            )}
   895→            title="Stampa"
   896→            aria-label="Stampa mappa mentale"
   897→          >
   898→            <Printer className="w-4 h-4" />
   899→          </button>
   900→        </div>
   901→      </div>
   902→
   903→      {/* Mindmap container - centered with pan/zoom support */}
   904→      <div
   905→        className={cn(
   906→          'flex items-center justify-center overflow-hidden relative',
   907→          settings.highContrast ? 'bg-black' : 'bg-white dark:bg-slate-900',
   908→          isFullscreen && 'flex-1'
   909→        )}
   910→        style={{
   911→          height: isFullscreen ? 'calc(100vh - 60px)' : '500px',
   912→          minHeight: isFullscreen ? 'calc(100vh - 60px)' : '400px',
   913→        }}
   914→      >
   915→        {error ? (
   916→          <div
   917→            className={cn(
   918→              'p-4 rounded-lg text-sm',
   919→              settings.highContrast
   920→                ? 'bg-red-900 border-2 border-red-500 text-white'
   921→                : 'bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-600 dark:text-red-400'
   922→            )}
   923→            role="alert"
   924→          >
   925→            <strong>Errore:</strong> {error}
   926→          </div>
   927→        ) : (
   928→          <>
   929→            <svg
   930→              ref={svgRef}
   931→              className={cn(
   932→                'absolute inset-0 w-full h-full cursor-grab active:cursor-grabbing',
   933→                !rendered && 'animate-pulse rounded-lg',
   934→                !rendered &&
   935→                  (settings.highContrast ? 'bg-gray-800' : 'bg-slate-100 dark:bg-slate-700/50')
   936→              )}
   937→              style={{ touchAction: 'none' }}
   938→            />
   939→            {rendered && (
   940→              <div className="absolute bottom-2 left-2 text-xs text-slate-400 dark:text-slate-500 pointer-events-none select-none">
   941→                Trascina per spostare • Scroll/pinch per zoom • Click sui nodi per espandere/comprimere
   942→              </div>
   943→            )}
   944→          </>
   945→        )}
   946→      </div>
   947→
   948→      {/* Screen reader description */}
   949→      <div className="sr-only" aria-live="polite">
   950→        {rendered && `Mappa mentale "${title}" renderizzata con ${nodes.length} nodi.`}
   951→      </div>
   952→    </motion.div>
   953→  );
   954→});
   955→
   956→// Export types for external use
   957→export type { MindmapNode };
   958→

