     1→'use client';
     2→
     3→import { useEffect, useRef } from 'react';
     4→import { motion, AnimatePresence } from 'framer-motion';
     5→import { Loader2, CheckCircle, XCircle, Code, BarChart2, GitBranch, Calculator, HelpCircle, Layers, Network } from 'lucide-react';
     6→import { CodeRunner } from './code-runner';
     7→import { ChartRenderer } from './chart-renderer';
     8→import { DiagramRenderer } from './diagram-renderer';
     9→import { FormulaRenderer } from './formula-renderer';
    10→import { QuizTool } from './quiz-tool';
    11→import { FlashcardTool } from './flashcard-tool';
    12→import { LiveMindmap } from './live-mindmap';
    13→import { cn } from '@/lib/utils';
    14→import type { ToolCall, CodeExecutionRequest, ChartRequest, DiagramRequest, FormulaRequest, QuizRequest, FlashcardDeckRequest, MindmapRequest } from '@/types';
    15→import { autoSaveMaterial } from '@/lib/hooks/use-saved-materials';
    16→
    17→// Auto-save utilities for tool results - now use database API
    18→function autoSaveMindmap(request: MindmapRequest): void {
    19→  autoSaveMaterial('mindmap', request.title, { nodes: request.nodes }, { subject: 'general' });
    20→}
    21→
    22→function autoSaveQuiz(request: QuizRequest): void {
    23→  autoSaveMaterial('quiz', request.title, { questions: request.questions }, { subject: request.subject });
    24→}
    25→
    26→function autoSaveFlashcards(request: FlashcardDeckRequest): void {
    27→  autoSaveMaterial('flashcard', request.name, { cards: request.cards }, { subject: request.subject });
    28→}
    29→
    30→interface ToolResultDisplayProps {
    31→  toolCall: ToolCall;
    32→  className?: string;
    33→  /** Session ID for real-time mindmap modifications (Maestro+Student collaboration) */
    34→  sessionId?: string | null;
    35→}
    36→
    37→const toolIcons: Record<string, React.ReactNode> = {
    38→  run_code: <Code className="w-4 h-4" />,
    39→  create_chart: <BarChart2 className="w-4 h-4" />,
    40→  create_diagram: <GitBranch className="w-4 h-4" />,
    41→  show_formula: <Calculator className="w-4 h-4" />,
    42→  create_visualization: <BarChart2 className="w-4 h-4" />,
    43→  create_quiz: <HelpCircle className="w-4 h-4" />,
    44→  create_flashcard: <Layers className="w-4 h-4" />,
    45→  create_mindmap: <Network className="w-4 h-4" />,
    46→};
    47→
    48→const toolNames: Record<string, string> = {
    49→  run_code: 'Code Execution',
    50→  create_chart: 'Chart',
    51→  create_diagram: 'Diagram',
    52→  show_formula: 'Formula',
    53→  create_visualization: 'Visualization',
    54→  create_quiz: 'Quiz',
    55→  create_flashcard: 'Flashcard',
    56→  create_mindmap: 'Mind Map',
    57→};
    58→
    59→export function ToolResultDisplay({ toolCall, className, sessionId }: ToolResultDisplayProps) {
    60→  const icon = toolIcons[toolCall.type] || <Code className="w-4 h-4" />;
    61→  const name = toolNames[toolCall.type] || toolCall.name;
    62→
    63→  return (
    64→    <motion.div
    65→      initial={{ opacity: 0, y: 10 }}
    66→      animate={{ opacity: 1, y: 0 }}
    67→      exit={{ opacity: 0, y: -10 }}
    68→      className={cn('space-y-2 w-full', className)}
    69→      role="region"
    70→      aria-label={`Tool result: ${name}`}
    71→    >
    72→      {/* Status header */}
    73→      <div className="flex items-center gap-2 text-sm">
    74→        <span className="text-slate-400">{icon}</span>
    75→        <span className="font-medium text-slate-300">{name}</span>
    76→        <StatusBadge status={toolCall.status} />
    77→      </div>
    78→
    79→      {/* Tool-specific content */}
    80→      <AnimatePresence mode="wait">
    81→        {toolCall.status === 'pending' && (
    82→          <motion.div
    83→            key="pending"
    84→            initial={{ opacity: 0 }}
    85→            animate={{ opacity: 1 }}
    86→            exit={{ opacity: 0 }}
    87→            className="h-20 flex items-center justify-center bg-slate-800/50 rounded-xl border border-slate-700"
    88→          >
    89→            <span className="text-sm text-slate-400">Waiting to execute...</span>
    90→          </motion.div>
    91→        )}
    92→
    93→        {toolCall.status === 'running' && (
    94→          <motion.div
    95→            key="running"
    96→            initial={{ opacity: 0 }}
    97→            animate={{ opacity: 1 }}
    98→            exit={{ opacity: 0 }}
    99→            className="h-20 flex items-center justify-center bg-slate-800/50 rounded-xl border border-slate-700"
   100→          >
   101→            <Loader2 className="w-6 h-6 text-blue-500 animate-spin" />
   102→          </motion.div>
   103→        )}
   104→
   105→        {(toolCall.status === 'completed' || toolCall.status === 'error') && (
   106→          <motion.div
   107→            key="result"
   108→            initial={{ opacity: 0, scale: 0.95 }}
   109→            animate={{ opacity: 1, scale: 1 }}
   110→            exit={{ opacity: 0, scale: 0.95 }}
   111→          >
   112→            <ToolContent toolCall={toolCall} sessionId={sessionId} />
   113→          </motion.div>
   114→        )}
   115→      </AnimatePresence>
   116→    </motion.div>
   117→  );
   118→}
   119→
   120→function StatusBadge({ status }: { status: ToolCall['status'] }) {
   121→  switch (status) {
   122→    case 'pending':
   123→      return (
   124→        <span className="px-2 py-0.5 text-xs rounded-full bg-slate-700 text-slate-400">
   125→          Pending
   126→        </span>
   127→      );
   128→    case 'running':
   129→      return (
   130→        <span className="px-2 py-0.5 text-xs rounded-full bg-blue-900/50 text-blue-400 flex items-center gap-1">
   131→          <Loader2 className="w-3 h-3 animate-spin" />
   132→          Running
   133→        </span>
   134→      );
   135→    case 'completed':
   136→      return (
   137→        <span className="px-2 py-0.5 text-xs rounded-full bg-green-900/50 text-green-400 flex items-center gap-1">
   138→          <CheckCircle className="w-3 h-3" />
   139→          Complete
   140→        </span>
   141→      );
   142→    case 'error':
   143→      return (
   144→        <span className="px-2 py-0.5 text-xs rounded-full bg-red-900/50 text-red-400 flex items-center gap-1">
   145→          <XCircle className="w-3 h-3" />
   146→          Error
   147→        </span>
   148→      );
   149→  }
   150→}
   151→
   152→function ToolContent({ toolCall, sessionId }: { toolCall: ToolCall; sessionId?: string | null }) {
   153→  switch (toolCall.type) {
   154→    case 'run_code':
   155→      return (
   156→        <CodeRunner
   157→          request={toolCall.arguments as unknown as CodeExecutionRequest}
   158→          autoRun
   159→        />
   160→      );
   161→
   162→    case 'create_chart':
   163→      return (
   164→        <ChartRenderer
   165→          request={toolCall.arguments as unknown as ChartRequest}
   166→        />
   167→      );
   168→
   169→    case 'create_diagram':
   170→      return (
   171→        <DiagramRenderer
   172→          request={toolCall.arguments as unknown as DiagramRequest}
   173→        />
   174→      );
   175→
   176→    case 'show_formula':
   177→      return (
   178→        <FormulaRenderer
   179→          request={toolCall.arguments as unknown as FormulaRequest}
   180→        />
   181→      );
   182→
   183→    case 'create_quiz':
   184→      return (
   185→        <AutoSaveQuiz request={toolCall.arguments as unknown as QuizRequest} />
   186→      );
   187→
   188→    case 'create_flashcard':
   189→      return (
   190→        <AutoSaveFlashcard request={toolCall.arguments as unknown as FlashcardDeckRequest} />
   191→      );
   192→
   193→    case 'create_mindmap':
   194→      return (
   195→        <AutoSaveMindmap
   196→          request={toolCall.arguments as unknown as MindmapRequest}
   197→          sessionId={sessionId}
   198→        />
   199→      );
   200→
   201→    default:
   202→      return (
   203→        <div className="p-4 rounded-xl bg-slate-800 border border-slate-700">
   204→          <pre className="text-sm text-slate-400 overflow-x-auto">
   205→            {JSON.stringify(toolCall.result || toolCall.arguments, null, 2)}
   206→          </pre>
   207→        </div>
   208→      );
   209→  }
   210→}
   211→
   212→// Auto-save wrapper components
   213→function AutoSaveQuiz({ request }: { request: QuizRequest }) {
   214→  const savedRef = useRef(false);
   215→  useEffect(() => {
   216→    if (!savedRef.current) {
   217→      savedRef.current = true;
   218→      autoSaveQuiz(request);
   219→    }
   220→  }, [request]);
   221→  return <QuizTool request={request} />;
   222→}
   223→
   224→function AutoSaveFlashcard({ request }: { request: FlashcardDeckRequest }) {
   225→  const savedRef = useRef(false);
   226→  useEffect(() => {
   227→    if (!savedRef.current) {
   228→      savedRef.current = true;
   229→      autoSaveFlashcards(request);
   230→    }
   231→  }, [request]);
   232→  return <FlashcardTool request={request} />;
   233→}
   234→
   235→function AutoSaveMindmap({ request, sessionId }: { request: MindmapRequest; sessionId?: string | null }) {
   236→  const savedRef = useRef(false);
   237→  useEffect(() => {
   238→    if (!savedRef.current) {
   239→      savedRef.current = true;
   240→      autoSaveMindmap(request);
   241→    }
   242→  }, [request]);
   243→  // Use LiveMindmap for real-time Maestro+Student collaboration on mindmaps
   244→  return (
   245→    <LiveMindmap
   246→      sessionId={sessionId ?? null}
   247→      title={request.title}
   248→      initialNodes={request.nodes}
   249→    />
   250→  );
   251→}
   252→
   253→// Multiple tools display
   254→interface ToolResultsListProps {
   255→  toolCalls: ToolCall[];
   256→  className?: string;
   257→  /** Session ID for real-time mindmap modifications (Maestro+Student collaboration) */
   258→  sessionId?: string | null;
   259→}
   260→
   261→export function ToolResultsList({ toolCalls, className, sessionId }: ToolResultsListProps) {
   262→  if (toolCalls.length === 0) return null;
   263→
   264→  return (
   265→    <div className={cn('space-y-4', className)} role="list" aria-label="Tool results">
   266→      <AnimatePresence>
   267→        {toolCalls.map((toolCall) => (
   268→          <ToolResultDisplay key={toolCall.id} toolCall={toolCall} sessionId={sessionId} />
   269→        ))}
   270→      </AnimatePresence>
   271→    </div>
   272→  );
   273→}
